module top_module(
    input clk,
    input rst,
    input [3:0] data_in,
    output [3:0] data_out
    );reg [3:0] invalid_data;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            invalid_data <= 4'd0;
        end
        else begin
            invalid_data <= data_in;
        end
    end

    assign data_out = invalid_data;

endmodule
